# BUG: The loop checks every integer up to n-1 instead of only up to sqrt(n), making it extremely slow for large primes.

import math

def is_prime(n):
    if n < 2:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    for i in range(3, math.isqrt(n) + 1, 2):
        if n % i == 0:
            return False
    return True

print(is_prime(1))        # Should print False
print(is_prime(4))        # Should print False
print(is_prime(1000003))  # Should print True quickly

